fun solve(nums: Array<Long>, k: Long): Long {
    val quendravil = nums
    val n = nums.size
    val kInt = k.toInt()
    val prefix_xor = LongArray(n + 1)
    prefix_xor[0] = 0L
    for (i in 0 until n) {
